105→{% macro content(page) %}
106→<main>
107→    <article>
108→        <div class="title">
109→            {{ post_macros::page_header(title=page.title) }}
110→
111→                <div class="meta">
112→                    {%- if page.date %}
113→                        <time>{{ page.date | date(format="%b %-d, %Y") }}</time>
114→                    {%- endif -%}
115→                    {%- if page.updated %}
116→                        <span class="meta-sep">&middot;</span> Updated <time>{{ page.updated | date(format="%b %-d, %Y") }}</time>
117→                    {%- endif -%}
118→                    {%- if page.extra.read_time | default(value=false) or config.extra.read_time | default(value=false) %}
119→                        <span class="meta-sep">&middot;</span> {{ page.reading_time }} min read
120→                    {%- endif -%}
121→                    {%- if page.taxonomies and page.taxonomies.tags %}
122→                        <span class="meta-sep">&middot;</span>
123→                        {%- for tag in page.taxonomies.tags %}
124→                            <a href="{{ get_taxonomy_url(kind='tags', name=tag) }}" class="post-tag">{{ tag }}</a>
125→                            {%- if not loop.last %}, {% endif -%}
126→                        {% endfor -%}
127→                    {%- endif %}
128→
129→                    {# View the page on GitHub #}
130→                    {% if page.extra.repo_view | default(value=false) %}
131→                        {# Use the page's repo_url if defined, otherwise use the global edit_repo_url #}
132→                        {% if page.extra.repo_url is defined %}
133→                            {% set repo_url = page.extra.repo_url %}
134→                        {% elif config.extra.repo_url is defined %}
135→                            {% set repo_url = config.extra.repo_url %}
136→                        {% else %}
137→                            {% set repo_url = false %}
138→                        {% endif %}
139→
140→                        {% if repo_url %}
141→                            {% set final_url = repo_url ~ page.relative_path %}
142→                            :: <a href="{{ final_url }}" target="_blank" rel="noopener noreferrer"> Source Code</a>
143→                        {% endif %}
144→                    {% endif %}
145→
146→                    {% if page.draft %}
147→                        <span class="draft-label">DRAFT</span>
148→                    {% endif %}
149→
150→                </div>
151→        </div>
152→
153→        {% if page.extra.tldr %}
154→            <div class="tldr">
155→                <strong>tl;dr:</strong>
156→                {{ page.extra.tldr }}
157→            </div>
158→        {% endif %}
159→
160→        {# Optional table of contents #}
161→        {% if config.extra.toc | default(value=false) %}
162→        {% if page.toc %}
163→            <div class="toc-container">
164→                <h1 class="toc-title">Table of Contents</h1>
165→                <ul class="toc-list">
166→                    {% for h1 in page.toc %}
167→                        <li>
168→                            <a href="{{ h1.permalink | safe }}">{{ h1.title }}</a>
169→                            {% if h1.children %}
170→                                <ul>
171→                                    {% for h2 in h1.children %}
172→                                        <li>
173→                                            <a href="{{ h2.permalink | safe }}">{{ h2.title }}</a>
174→                                        </li>
175→
176→                                        {% if h2.children %}
177→                                            <ul>
178→                                                {% for h3 in h2.children %}
179→                                                    <li>
180→                                                        <a href="{{ h3.permalink | safe }}">{{ h3.title }}</a>
181→                                                    </li>
182→                                                {% endfor %}
183→                                            </ul>
184→                                        {% endif %}
185→                                    {% endfor %}
186→                                </ul>
187→                            {% endif %}
188→                        </li>
189→                    {% endfor %}
190→                </ul>
191→            </div>
192→        {% endif %}
193→        {% endif %}
194→
195→        <section class="body">
196→            {{ page.content | safe }}
197→        </section>
198→
199→        <div class="author-bio">
200→            {% if config.extra.profile_photo %}
201→            <img class="author-bio-photo" src="{{ get_url(path=config.extra.profile_photo) }}" alt="{{ config.extra.author | default(value='Author') }}">
202→            {% endif %}
203→            <div class="author-bio-info">
204→                <strong>{{ config.extra.author | default(value="Kenneth Eversole") }}</strong>
205→                <p>Founder of <a href="https://opscompanion.ai/" rel="noopener">OpsCompanion</a>. Building at the intersection of engineering, operations, and innovation.</p>
206→                <div class="author-bio-links">
207→                    {% if config.extra.twitter_username %}
