209→                    {% endif %}
210→                    {% if config.extra.linkedin %}
211→                    <a href="https://linkedin.com/in/{{ config.extra.linkedin }}" rel="noopener noreferrer">LinkedIn</a>
212→                    {% endif %}
213→                    {% if config.extra.github %}
214→                    <a href="https://github.com/{{ config.extra.github }}" rel="noopener noreferrer">GitHub</a>
215→                    {% endif %}
216→                </div>
217→            </div>
218→        </div>
219→
220→        <div class="share-links">
